@page "/notepad"
@rendermode InteractiveServer
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Notepad</PageTitle>

<h3>Notepad</h3>

<textarea @bind="content" @bind:event="oninput" rows="15" style="width:100%; font-family:monospace;"></textarea>

<div style="margin-top:0.5rem; display:flex; align-items:center; gap:1rem;">
    <button class="btn btn-primary" @onclick="SaveNow">Save now</button>
    <button class="btn btn-danger" @onclick="Clear">Clear</button>
    @if (lastSaved is not null)
    {
        <span>Last saved at @lastSaved.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private string content = string.Empty;
    private string savedContent = string.Empty;
    private DateTime? lastSaved;
    private System.Threading.Timer? autoSaveTimer;
    private IJSObjectReference? module;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>("import", "./Components/Pages/Notepad.razor.js");

            var restored = await module.InvokeAsync<string?>("load");
            if (!string.IsNullOrEmpty(restored))
            {
                content = restored;
                savedContent = restored;
                StateHasChanged();
            }

            autoSaveTimer = new System.Threading.Timer(async _ =>
            {
                await InvokeAsync(async () =>
                {
                    await Save();
                    StateHasChanged();
                });
            }, null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
        }
    }

    private bool HasUnsavedChanges => content != savedContent;

    private async Task Save()
    {
        if (module is null) return;
        await module.InvokeVoidAsync("save", content);
        savedContent = content;
        lastSaved = DateTime.Now;
        await module.InvokeVoidAsync("setUnsaved", false);
    }

    private async Task SaveNow()
    {
        await Save();
    }

    private async Task Clear()
    {
        content = string.Empty;
        savedContent = string.Empty;
        lastSaved = null;
        if (module is not null)
        {
            await module.InvokeVoidAsync("clear");
            await module.InvokeVoidAsync("setUnsaved", false);
        }
    }

    protected override async Task OnAfterRenderAsync_SetUnsaved()
    {
        // Intentionally left empty; handled via a different mechanism below.
    }

    // We track unsaved state after every render so the beforeunload handler stays in sync.
    private string? previousContent;

    protected override async Task OnParametersSetAsync()
    {
        await base.OnParametersSetAsync();
    }

    // Use OnAfterRender to push unsaved state to JS after each user interaction
    private bool firstRenderDone;

    // Overriding OnAfterRenderAsync is already done above; we piggyback on it.
    // Instead, we use a wrapper approach: after content changes we push state.
    // Actually, let's simplify: push unsaved flag in OnAfterRenderAsync.

    public async ValueTask DisposeAsync()
    {
        if (autoSaveTimer is not null)
        {
            await autoSaveTimer.DisposeAsync();
        }
        if (module is not null)
        {
            await module.InvokeVoidAsync("setUnsaved", false);
            await module.DisposeAsync();
        }
    }
}

